import json, pandas as pd

def parse_date(s: str):
    if s is None:
        return pd.NaT
    s = str(s)
    # try a set of common formats observed
    fmts = [
        '%Y-%m-%d',
        '%Y-%m-%d %H:%M:%S',
        '%d %b %Y, %H:%M',
        '%B %d, %Y at %I:%M %p',
    ]
    for f in fmts:
        try:
            return pd.to_datetime(s, format=f)
        except Exception:
            pass
    # fallback
    return pd.to_datetime(s, errors='coerce')

